// In a Code node after AI Agent
const aiOutput = $input.first().json. output;

// Parse the JSON string
const parsed = JSON.parse(aiOutput);

return {
  reply: parsed.reply,           // Display this to user
  lead_status: parsed. lead_status,  // Use for routing
  human_needed: parsed. human_needed // Use for routing
};

// Parse the AI Agent output
const aiOutput = $('AI Agent1').item.json.output;

let parsed;
try {
  // Clean the output - remove markdown code blocks if present
  let cleanOutput = aiOutput;
  if (cleanOutput.includes('```json')) {
    cleanOutput = cleanOutput. replace(/```json\n?/g, '').replace(/```\n?/g, '');
  }
  if (cleanOutput.includes('```')) {
    cleanOutput = cleanOutput.replace(/```\n?/g, '');
  }

  parsed = JSON.parse(cleanOutput. trim());
} catch (error) {
  // If parsing fails, return default structure
  parsed = {
    reply: aiOutput,
    lead_status: "COLD",
    human_needed: false,
    lead_data: {
      firstname: null,
      lastname: null,
      email:  null,
      phone: null,
      service_interest: null,
      company: null,
      is_complete: false
    }
  };
}

return {
  json: {
    reply: parsed.reply || aiOutput,
    lead_status: parsed. lead_status || "COLD",
    human_needed: parsed. human_needed || false,
    lead_data: parsed.lead_data || {
      firstname: null,
      lastname: null,
      email: null,
      phone: null,
      service_interest: null,
      company: null,
      is_complete: false
    },
    sessionId:  $('When chat message received').item.json.sessionId
  }
};

